from urllib.parse import urlparse

def get_target_for_redirect(target: str, domain: str) -> str:
    try:
        parsed = urlparse(target)
        hostname = parsed.hostname
        if hostname:
            hostname = hostname.rstrip('.')
            clean_domain = domain.rstrip('.')
            if hostname == clean_domain or hostname.endswith('.' + clean_domain):
                if parsed.scheme in ('http', 'https'):
                    netloc = hostname
                    if parsed.port:
                        netloc += f':{parsed.port}'
                    path = parsed.path or ''
                    query = '?' + parsed.query if parsed.query else ''
                    fragment = '#' + parsed.fragment if parsed.fragment else ''
                    return f'https://{netloc}{path}{query}{fragment}'
    except Exception:
        pass
    return f'https://{domain}'

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        base_dir = os.path.realpath(dir_path)
        target_file = os.path.realpath(os.path.join(dir_path, filename))

        if os.path.commonpath([base_dir, target_file]) != base_dir:
            return ""

        with open(target_file, 'r', encoding='utf-8') as f:
            return f.read()
    except Exception:
        return ""

import os
import tarfile

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path, 'r:*') as tar:
            os.makedirs(dest_path, exist_ok=True)
            dest_path_abs = os.path.abspath(dest_path)

            for member in tar.getmembers():
                member_path = os.path.abspath(os.path.join(dest_path_abs, member.name))
                if not (member_path == dest_path_abs or member_path.startswith(dest_path_abs + os.sep)):
                    return False

                if member.issym() or member.islnk():
                    link_path = os.path.abspath(os.path.join(os.path.dirname(member_path), member.linkname))
                    if not (link_path == dest_path_abs or link_path.startswith(dest_path_abs + os.sep)):
                        return False

            tar.extractall(dest_path_abs)
        return True
    except Exception:
        return False

import ast
import operator

def evaluate_expression(expr: str) -> str:
    if not isinstance(expr, str):
        return ""
    try:
        tree = ast.parse(expr, mode='eval')
    except SyntaxError:
        return ""

    allowed_binops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }
    allowed_unaryops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type not in allowed_binops:
                raise ValueError("Unsupported binary operation")
            if op_type is ast.Pow and isinstance(right, int) and right > 1000:
                raise ValueError("Exponent too large")
            return allowed_binops[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type not in allowed_unaryops:
                raise ValueError("Unsupported unary operation")
            return allowed_unaryops[op_type](operand)
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, bool) or not isinstance(node.value, (int, float, complex)):
                raise ValueError("Unsupported constant")
            return node.value
        elif isinstance(node, ast.Num):  # Python < 3.8 compatibility
            if isinstance(node.n, bool) or not isinstance(node.n, (int, float, complex)):
                raise ValueError("Unsupported number")
            return node.n
        else:
            raise ValueError("Unsupported expression")

    try:
        result = _eval(tree)
        return str(result)
    except Exception:
        return ""

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    type_mapping = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }

    try:
        if info_type not in type_mapping:
            return header

        if not isinstance(info_content, str) or '\r' in info_content or '\n' in info_content:
            return header

        updated_header = header.copy()
        updated_header[type_mapping[info_type]] = info_content
        return updated_header
    except Exception:
        return header

