import io
import importlib

class RestrictedUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        allowed_modules = {
            'builtins': ['range', 'complex', 'bytes', 'bytearray', 'memoryview', 'str', 'int', 'float', 'list', 'tuple', 'dict', 'set', 'frozenset', 'bool'],
            'collections': ['OrderedDict', 'defaultdict'],
            'datetime': ['datetime', 'date', 'time', 'timedelta'],
            'decimal': ['Decimal']
        }
        if module in allowed_modules and name in allowed_modules[module]:
            mod = importlib.import_module(module)
            return getattr(mod, name)
        raise pickle.UnpicklingError("global '%s.%s' is forbidden" % (module, name))

def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if isinstance(pickled, str):
        pickled = pickled.encode('latin-1')
    return RestrictedUnpickler(io.BytesIO(pickled)).load()

