import json
import base64

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token = json.loads(decoded)
    except Exception:
        return None

    if isinstance(token, dict):
        if token.get('is_valid'):
            return token.get('data', token)
        elif token.get('valid'):
            return token.get('data', token)
    return None
